const body = $json.body ?? $json;
const input = body.input;
if (!input?.member || !Array.isArray(input?.tasks)) throw new Error('Missing quiz input');
const taskLines = input.tasks.map((task, index) => `${index + 1}. ${task.title}: ${task.description ?? 'No description'} (status: ${task.status})`).join('\n');
return [{ json: { input, prompt: `Create exactly 5 serious ABCD multiple-choice quiz questions for ${input.member.displayName ?? 'this student'} based on the project tasks they completed. The questions must test understanding of purpose, requirements, deliverables, quality criteria, dependencies, risks, or implementation decisions from the task descriptions. Do NOT ask which task they were assigned to. Do NOT make every answer option A. Distribute correctOption across A, B, C, and D. Use only these tasks:\n${taskLines}\nReturn JSON only with {"questions":[{"id":"q1","prompt":"...","options":["A text","B text","C text","D text"],"correctOption":"A"}]}. Each options array must have exactly 4 concise options. Every correctOption must be one of A, B, C, D.` } }];

const raw = $json.output ?? $json.text ?? $json;
const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
const questions = Array.isArray(parsed.questions) ? parsed.questions : [];
return [{ json: { questions: questions.slice(0, 5) } }];
